    }

    const topScope = sc[sc.length - 1];
    if (!topScope) throw new Error("Internal error: empty scope stack");
    topScope[name] = { value: value.value, type: explicitType ?? value.type };

    if (s.pos < tokens.length && tokens[s.pos] === ";") {
      s.pos++; // consume ';'
    }
  }"}

